import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']),
  PORT: z.string().regex(/^\d+$/).transform(Number),
  DATABASE_URL: z.string().url(),
  JWT_SECRET: z.string().min(10),
  RATE_LIMIT_WINDOW: z.string().regex(/^\d+$/).transform(Number),
  RATE_LIMIT_MAX: z.string().regex(/^\d+$/).transform(Number)
});

type Env = z.infer<typeof envSchema>;

export const env: Env = envSchema.parse(process.env);

import helmet from 'helmet';
import cors from 'cors';
import rateLimit from 'express-rate-limit';
import { env } from '../config/env';
import express from 'express';

export const applySecurityMiddlewares = (app: express.Application) => {
  app.use(helmet());
  app.use(cors({ origin: 'http://your-allowed-origin.com' }));
  app.use(rateLimit({
    windowMs: env.RATE_LIMIT_WINDOW * 60 * 1000, // minutes
    max: env.RATE_LIMIT_MAX,
    message: 'Too many requests, please try again later.'
  }));
};

export interface BaseDTO<T> {
  fromEntityToDTO(entity: T): any;
  fromDTOToEntity(dto: any): T;
}

// Example for a User DTO
type User = {
  id: string;
  username: string;
  email: string;
};

export class UserDTO implements BaseDTO<User> {
  fromEntityToDTO(entity: User): any {
    return { id: entity.id, username: entity.username, email: entity.email };
  }

  fromDTOToEntity(dto: any): User {
    return { id: dto.id, username: dto.username, email: dto.email };
  }
}

import { Request, Response, NextFunction } from 'express';
import { logger } from '../logger';

export const errorHandler = (error: any, req: Request, res: Response, next: NextFunction) => {
  const status = error.status || 500;
  const message = error.message || 'Internal Server Error';

  logger.error({
    message,
    status,
    requestId: req.headers['x-request-id'],
    path: req.path,
    timestamp: new Date().toISOString(),
  });

  res.status(status).json({ error: message });
};

import { createLogger, format, transports } from 'winston';

export const logger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  defaultMeta: { service: 'user-service' },
  transports: [
    new transports.Console(),
  ],
});

import express from 'express';
import { applySecurityMiddlewares } from './middlewares/security';
import { errorHandler } from './handlers/error-handler';
import { logger } from './logger';
import('./config/env'); // Validate env variables

const app = express();

applySecurityMiddlewares(app);

// Application routes go here

app.use(errorHandler);

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(`Server running at http://localhost:${PORT}`);
});
